class Solution {
    void dfs(Node* n, vector<int>& ans) {
        if (!n) return;
        ans.push_back(n->val);
        for (auto* c : n->children) dfs(c, ans);
    }
public:
    vector<int> preorder(Node* root) {
        vector<int> ans;
        dfs(root, ans);
        return ans;
    }
};
